import{_ as e}from"./chunks/project-settings_01.CuuUlwv5.js";import{_ as o,o as a,c as l,a2 as d}from"./chunks/framework.DnrXFDHb.js";const x=JSON.parse('{"title":"Project Settings","description":"","frontmatter":{},"headers":[],"relativePath":"ru/configuration/project-settings.md","filePath":"ru/configuration/project-settings.md"}'),n={name:"ru/configuration/project-settings.md"};function s(r,t,i,c,g,h){return a(),l("div",null,[...t[0]||(t[0]=[d('<h1 id="project-settings" tabindex="-1"><i class="ph-fill ph-gear-six"></i> Project Settings <a class="header-anchor" href="#project-settings" aria-label="Permalink to &quot;&lt;i class=&quot;ph-fill ph-gear-six&quot;&gt;&lt;/i&gt; Project Settings&quot;">​</a></h1><p>Все глобальные настройки WebAP централизованы в одном месте: <strong>Edit -&gt; Project Settings -&gt; Adaptive Performance (Web)</strong></p><p><img src="'+e+'" alt=""></p><h2 id="general-settings" tabindex="-1">General Settings <a class="header-anchor" href="#general-settings" aria-label="Permalink to &quot;General Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Параметр</th><th style="text-align:left;">Описание</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Target Min FPS</strong></td><td style="text-align:left;">Базовая линия производительности.• Если текущий FPS опускается ниже этого значения (с учетом запаса), плагин начинает снижать качество графики.• Если FPS стабильно держится выше, плагин пытается повысить качество.<em>Рекомендация:</em> Устанавливайте реалистичные значения. Для WebGL стандартом де-факто является <code>60</code>, но для тяжелых 3D-проектов можно использовать <code>30</code>.</td></tr></tbody></table><h2 id="indexer-settings" tabindex="-1">Indexer Settings <a class="header-anchor" href="#indexer-settings" aria-label="Permalink to &quot;Indexer Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Параметр</th><th style="text-align:left;">Описание</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Decrease Cooldown</strong></td><td style="text-align:left;">Время (в секундах), которое система ждет после <em>снижения</em> качества, прежде чем снова оценивать FPS. <em>Рекомендация:</em> Должно быть коротким (<code>1.0</code> - <code>2.0</code> сек). Системе нужно быстро реагировать на лаги и &quot;сбрасывать балласт&quot;, пока FPS не стабилизируется.</td></tr><tr><td style="text-align:left;"><strong>Increase Cooldown</strong></td><td style="text-align:left;">Время ожидания после <em>повышения</em> качества.<em>Рекомендация:</em> Должно быть длинным (<code>5.0</code> - <code>10.0</code> сек). Прежде чем снова нагружать систему, нужно убедиться, что предыдущее повышение графики не дестабилизировало кадр.</td></tr></tbody></table><h2 id="anti-yo-yo-penalty-system" tabindex="-1">Anti Yo-Yo Penalty System <a class="header-anchor" href="#anti-yo-yo-penalty-system" aria-label="Permalink to &quot;Anti Yo-Yo Penalty System&quot;">​</a></h2><p>Защищает от &quot;пин-понга&quot;, когда качество бесконечно переключается между двумя уровнями.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Параметр</th><th style="text-align:left;">Описание</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Detection Window</strong></td><td style="text-align:left;">Время, в течение которого система пристально следит за FPS после <em>увеличения</em> качества. Если в этот период происходит просадка FPS, система расценивает это как эффект Yo-Yo.</td></tr><tr><td style="text-align:left;"><strong>Penalty Lockout Duration</strong></td><td style="text-align:left;">Штрафное время (например, <code>60</code> секунд), на которое полностью блокируются любые попытки <em>повысить</em> качество.</td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title"><i class="ph-bold ph-note-pencil"></i> NOTE</p><p>Штраф блокирует только повышения (Increase). Если FPS снова упадет, система всё равно сможет экстренно снизить качество (Decrease).</p></div><h2 id="scalers" tabindex="-1">Scalers <a class="header-anchor" href="#scalers" aria-label="Permalink to &quot;Scalers&quot;">​</a></h2><p>Каждый добавленный скейлер имеет базовый набор параметров. Эти параметры определяют его «стоимость» (Cost) для системы. Плагин автоматически вычисляет эту стоимость в реальном времени: скейлеры с наименьшим визуальным влиянием и подходящим таргетом (CPU/GPU) идут в работу первыми.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Параметр</th><th style="text-align:left;">Описание</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Max Level</strong></td><td style="text-align:left;">Количество дискретных шагов (уровней) между базовым и минимальным качеством. Например, <code>Max Level = 4</code> означает, что у скейлера есть 4 ступени деградации.</td></tr><tr><td style="text-align:left;"><strong>Min Bound</strong></td><td style="text-align:left;">Минимальное значение масштаба (применяется, когда скейлер достигает своего <code>Max Level</code>). Например, <code>0.5</code> означает снижение качества до 50% от оригинала.</td></tr><tr><td style="text-align:left;"><strong>Max Bound</strong></td><td style="text-align:left;">Максимальное значение масштаба. Обычно равно <code>1.0</code> (100% качества), это значение по умолчанию на Level 0.</td></tr><tr><td style="text-align:left;"><strong>Visual Impact</strong></td><td style="text-align:left;">Визуальное влияние на картинку (<code>Low</code>, <code>Medium</code>, <code>High</code>). Плагин всегда в первую очередь повышает уровни (снижает качество) у скейлеров с <code>Low</code> импактом.</td></tr><tr><td style="text-align:left;"><strong>Target</strong></td><td style="text-align:left;">Определяет, какую подсистему оптимизирует скейлер (<code>CPU</code>, <code>GPU</code> или обе). Если текущий Bottleneck системы это <code>CPU</code>, плагин будет игнорировать <code>GPU</code>-скейлеры.</td></tr><tr><td style="text-align:left;"><strong>Target Tags</strong></td><td style="text-align:left;">Некоторые специфичные скейлеры (<code>WebResolutionScaler</code>, <code>WebCameraClipScaler</code>, <code>WebLayerCullingScaler</code>) применяют свои настройки не глобально, а к конкретным камерам на сцене.</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Использование Camera Tags</p><p>Эти скейлеры не используют вызов <code>Camera.main</code>. Вместо этого они сканируют активные камеры по массиву <code>Target Tags</code>.</p><p>По умолчанию там указан тег <code>MainCamera</code>. <strong>Если в вашей игре используются кастомные теги для камер (например, <code>PlayerCamera</code>), вы обязаны добавить их в настройки скейлера.</strong> Иначе масштабирование для этих камер не сработает.</p></div><h2 id="development-settings" tabindex="-1">Development Settings <a class="header-anchor" href="#development-settings" aria-label="Permalink to &quot;Development Settings&quot;">​</a></h2><p>Этот блок предназначен исключительно для отладки поведения плагина в браузере или редакторе.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Параметр</th><th style="text-align:left;">Описание</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Logging</strong></td><td style="text-align:left;">Включает подробное логирование работы плагина в консоль браузера (или консоль Unity). Выводит сообщения об изменении Bottleneck&#39;ов, срабатывании скейлеров и активации Anti Yo-Yo штрафов.</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Оптимизация</p><p>Логирование использует внутреннюю обертку <code>DebugWebAP</code>. Рекомендуется отключать <code>Logging</code> в финальных релизных (Production) сборках для экономии ресурсов и чистоты консоли.</p></div>',19)])])}const m=o(n,[["render",s]]);export{x as __pageData,m as default};
